args.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
SELECT ?volume
WHERE {
  ?mound wdt:P31 wd:Q473838;
         wdt:P1073 wd:Q355841;
         wdt:P2234 ?volume.
}
ORDER BY DESC(?volume)
LIMIT 1

